pub(super) fn native_plugin_load_manifest_template(package_ids: &[String]) -> String {
    let mut output = String::from(
        "# Generated by Zircon export. Native dynamic plugins are loaded from these packages.\n",
    );
    for package_id in package_ids {
        let package_directory = native_dynamic_package_directory(package_id);
        output.push_str("\n[[plugins]]\n");
        output.push_str(&format!("id = {package_id:?}\n"));
        output.push_str(&format!(
            "path = {:?}\n",
            format!("plugins/{package_directory}")
        ));
        output.push_str(&format!(
            "manifest = {:?}\n",
            format!("plugins/{package_directory}/plugin.toml")
        ));
    }
    output
}

pub(super) fn native_dynamic_package_directory(package_id: &str) -> String {
    let sanitized: String = package_id
        .chars()
        .map(|ch| {
            if ch.is_ascii_alphanumeric() || ch == '-' || ch == '_' {
                ch
            } else {
                '_'
            }
        })
        .collect();
    if sanitized.is_empty() {
        "_".to_string()
    } else {
        sanitized
    }
}
